from __future__ import annotations

import json
from os import PathLike
from typing import Union, Dict, Any, Iterable, Tuple, IO, Type
from zipfile import ZipFile

from typing_extensions import TypedDict, NotRequired, Literal

JSON_PATH = "index.json"


class Bundle(TypedDict):
    """A dictionary that contains data required to instantiate a :class:`Stage`"""

    name: NotRequired[str]
    """The name of the Stage's class the bundle relates to"""
    version: NotRequired[str]
    """The version of the bundled data, in a semantic versioning fashion: `x.y.z`"""
    database: Dict[str, Any]
    """The :class:`Stage` specific data contained in the `Bundle`"""


BundleKeys = Literal["name", "version", "database"]
"""The keys defined in :class:`Bundle`"""


def _iter_json_obj(obj: Dict[str, Any]) -> Iterable[Tuple[Any, str]]:
    for key, child in obj.items():
        if isinstance(child, dict):
            yield from _iter_json_obj(child)
        else:
            yield obj, key


def _is_serializable(obj: Any) -> bool:
    try:
        json.dumps(obj)
    except TypeError:
        return False
    return True


def from_file(file: Union[str, PathLike, IO[bytes]]) -> Bundle:
    with ZipFile(file, "r") as zipfile:
        obj: Any = json.loads(zipfile.read(JSON_PATH))
        if not isinstance(obj, dict):
            raise ValueError(f"The {JSON_PATH} file must contain a dictionary")
        name_set = set(zipfile.namelist())
        name_set.discard(JSON_PATH)
        for dictionary, key in _iter_json_obj(obj):
            if key in name_set:
                dictionary[key] = zipfile.read(key)

    bundle: Bundle = {"database": obj["database"]}

    def add_not_required_field(_key: BundleKeys, expected_type: Type) -> None:
        try:
            value: Any = obj[_key]
        except KeyError:
            return
        else:
            if isinstance(value, expected_type):
                bundle[_key] = value
            else:
                raise ValueError(
                    f"The '{_key}' field of {file} has an invalid type: expected `{expected_type}`, "
                    f"found `{type(value)}`"
                )

    add_not_required_field("version", expected_type=str)
    add_not_required_field("name", expected_type=str)
    return bundle


def to_file(file: Union[str, PathLike, IO[bytes]], obj: Dict[str, Any]) -> None:
    with ZipFile(file, "w") as zipfile:
        for dictionary, key in _iter_json_obj(obj):
            if not _is_serializable(dictionary[key]):
                zipfile.writestr(key, dictionary[key])
                dictionary[key] = key
        zipfile.writestr(JSON_PATH, json.dumps(obj, indent=4))
